                                <button className="text-white/50 shrink-0 p-2"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* Menus... */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
