                                   {/* Handle */}
                                   <div className="w-full flex justify-center pt-3 pb-6" onClick={() => setIsMoreMenuOpen(false)}>
                                       <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                   </div>

                                   <div className="px-6 pb-12">
                                       {/* Song Info */}
                                       <div className="flex items-center gap-4 mb-8">
                                           <img src={imageUrl} className="w-14 h-14 rounded-md object-cover shadow-lg" alt="" />
