                                               <h3 className="text-white font-bold text-[17px] leading-tight mb-1 line-clamp-1">{currentSong.name}</h3>
                                               <p className="text-[#B3B3B3] text-sm font-medium">{currentSong.artists.primary[0]?.name}</p>
                                           </div>
                                       </div>

                                       {/* Download Box */}
                                       <div className="bg-[#2A2A2A] rounded-xl overflow-hidden mb-6 active:scale-[0.99] transition-transform">
