                                            >
                                                <div className="flex items-center gap-4">
                                                     <div className="w-10 h-10 rounded-full bg-[#121212] flex items-center justify-center text-white">
                                                         <Download size={20} />
                                                     </div>
                                                     <div className="flex flex-col">
                                                         <span className="font-bold text-white text-[15px]">Download</span>
                                                         <span className="text-[12px] text-[#B3B3B3] font-medium">Tap to choose quality</span>
                                                     </div>
                                                </div>
                                                <ChevronDown size={22} className={`text-[#B3B3B3] transition-transform duration-300 ${isDownloadExpanded ? 'rotate-180' : ''}`} />
                                            </div>

                                            <AnimatePresence>
                                                {isDownloadExpanded && (
                                                    <motion.div 
                                                        initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }}
                                                        transition={{ duration: 0.2 }}
                                                        className="bg-[#222]"
                                                    >
                                                        <div className="h-[1px] bg-white/5 mx-4"></div>
                                                        {currentSong.downloadUrl && currentSong.downloadUrl.length > 0 ? (
                                                             currentSong.downloadUrl.map(opt => (
                                                                <button 
                                                                    key={opt.quality} 
                                                                    onClick={() => handleDownloadSelect(opt.url, opt.quality)} 
                                                                    className="w-full flex items-center justify-between px-6 py-4 text-[14px] text-white/90 hover:bg-white/5"
                                                                >
                                                                    <span className="font-medium capitalize">{opt.quality}</span>
                                                                    <Download size={16} className="text-[#B3B3B3]" />
                                                                </button>
                                                             ))
                                                        ) : (
                                                             <div className="p-4 text-xs text-center text-[#777]">Checking for streams...</div>
                                                        )}
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                       </div>

                                       {/* Menu List */}
                                       <div className="flex flex-col">
                                           {/* Like */}
                                           <button onClick={() => toggleLike(currentSong)} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <Heart size={26} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-[#B3B3B3]"} />
                                               <span className={`text-[16px] font-medium ${isLiked ? "text-[#1DB954]" : "text-white"}`}>{isLiked ? 'Liked' : 'Like'}</span>
                                           </button>

                                           {/* Add to Queue */}
                                           <button onClick={handleAddToQueue} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <ListPlus size={26} className="text-[#B3B3B3]" />
                                               <span className="text-[16px] font-medium text-white">Add to queue</span>
                                           </button>

                                           {/* Share */}
                                           <button onClick={handleShare} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <Share2 size={26} className="text-[#B3B3B3]" />
                                               <span className="text-[16px] font-medium text-white">Share</span>
                                           </button>

                                           {/* View Artist */}
                                           <button onClick={handleViewArtist} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <User size={26} className="text-[#B3B3B3]" />
                                               <span className="text-[16px] font-medium text-white">View Artist</span>
                                           </button>

                                           {/* View Album */}
                                           <button onClick={handleViewAlbum} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <Disc size={26} className="text-[#B3B3B3]" />
                                               <span className="text-[16px] font-medium text-white">View Album</span>
                                           </button>

                                           {/* Sleep Timer */}
                                           <button onClick={toggleSleepTimer} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <Moon size={26} className={sleepTimerId ? "text-[#1DB954]" : "text-[#B3B3B3]"} />
                                               <span className={`text-[16px] font-medium ${sleepTimerId ? "text-[#1DB954]" : "text-white"}`}>
                                                   {sleepTimerId ? 'Sleep Timer (On)' : 'Sleep Timer (30 mins)'}
                                               </span>
                                           </button>

                                           {/* Song Radio */}
                                           <button onClick={handleSongRadio} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <Radio size={26} className="text-[#B3B3B3]" />
                                               <span className="text-[16px] font-medium text-white">Go to Song Radio</span>
                                           </button>

                                           {/* Credits */}
                                           <button onClick={() => { alert("VibeStream Web Player\nBuilt with ❤️"); setIsMoreMenuOpen(false); }} className="flex items-center gap-5 py-4 active:bg-white/5 -mx-4 px-4 rounded-lg transition-colors">
                                               <Info size={26} className="text-[#B3B3B3]" />
                                               <span className="text-[16px] font-medium text-white">Show credits</span>
                                           </button>
                                       </div>
                                   </div>
                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: "100%", opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: "100%", opacity: 0 }}
                    transition={transitionSpec}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                    style={{ transform: 'translateZ(0)' }}
                >
                    <motion.div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden" 
                        animate={{ backgroundColor: dominantColor }}
                    >
                        <div className="absolute inset-0 bg-black/20" />
                    </motion.div>

                    <div className="flex items-center h-full px-2 gap-3">
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden">
                            <img 
                                src={imageUrl} 
                                alt="" 
                                className="w-full h-full object-cover" 
                            />
                        </div>

                        <div className="flex-1 min-w-0 pr-2 flex flex-col justify-center">
                            <div className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </div>
                            <div className="text-white/70 text-[10px] truncate">
                                {currentSong.artists.primary[0]?.name}
                            </div>
                        </div>

                        <div className="flex items-center gap-1.5 shrink-0">
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="p-1.5"><Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} /></button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); togglePlay(); }} 
                                className="p-1.5 text-white"
                            >
                                {isBuffering ? <Loader2 size={24} className="animate-spin" /> : isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} fill="white" />}
                            </button>
                        </div>
                    </div>
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div ref={miniProgressRef} className="h-full bg-white rounded-full" style={{ width: '0%' }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    </>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { uploadToCloudinary } from '../services/api';
import { ArrowLeft, Camera, Loader2, LogOut, Cloud, SignalHigh, SignalMedium, SignalLow, Music2, Users, ChevronRight, Mail, Shield, RotateCcw, Youtube, Library, Globe, Layers, DownloadCloud } from 'lucide-react';
import { motion } from 'framer-motion';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.08,
      delayChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { 
    opacity: 1, 
    y: 0,
    transition: { type: "spring", stiffness: 300, damping: 30 }
  }
};

const heroVariants = {
  hidden: { opacity: 0, scale: 0.9 },
  visible: { 
    opacity: 1, 
    scale: 1,
    transition: { type: "spring", stiffness: 200, damping: 20 }
  }
};

export const Profile: React.FC = () => {
  const { currentUser, updateUserProfile, logoutUser, streamingQuality, setStreamingQuality, favoriteArtists, musicSource, setMusicSource } = usePlayerStore();
  const navigate = useNavigate();

  const [name, setName] = useState('');
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const [scrollOpacity, setScrollOpacity] = useState(0);

  // App Update State
  const [checkingUpdate, setCheckingUpdate] = useState(false);
  const [updateAvailable, setUpdateAvailable] = useState(false);
  const currentVersion = "2.4.0";

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentUser) {
      setName(currentUser.name);
      setImagePreview(currentUser.image || null);
    } else {
      navigate('/login');
    }
  }, [currentUser, navigate]);

  useEffect(() => {
    const handleScroll = () => {
        const opacity = Math.min(window.scrollY / 200, 1);
        setScrollOpacity(opacity);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    try {
      let imageUrl = imagePreview;
      if (imageFile) {
        imageUrl = await uploadToCloudinary(imageFile);
      }
      updateUserProfile(name, imageUrl || undefined);
      await new Promise(r => setTimeout(r, 800)); // UX delay
      alert('Profile updated');
    } catch (error) {
      console.error("Failed to update profile", error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    if(window.confirm('Are you sure you want to log out?')) {
        logoutUser();
        navigate('/');
    }
  };

  const handleCheckUpdate = () => {
      setCheckingUpdate(true);
      setTimeout(() => {
          setCheckingUpdate(false);
          // Simulate 50/50 chance of update for demo
          const isAvailable = Math.random() > 0.5;
          setUpdateAvailable(isAvailable);
          if (!isAvailable) {
              alert("You are already on the latest version.");
          }
      }, 2000);
  };

  const handleUpdate = () => {
      if (confirm("Install update and restart?")) {
          window.location.reload();
      }
  };

  if (!currentUser) return null;

  return (
    <div className="min-h-full bg-[#121212] text-white pb-32 relative isolate">

      {/* Background Gradient */}
      <div className="absolute top-0 left-0 right-0 h-[400px] bg-gradient-to-b from-[#535353] to-[#121212] -z-10" />

      {/* Sticky Header */}
      <div 
        className="sticky top-0 z-40 px-6 py-4 flex items-center justify-between transition-colors duration-200"
        style={{ backgroundColor: `rgba(18, 18, 18, ${scrollOpacity})` }}
      >
          <button 
              onClick={() => navigate(-1)} 
              className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-colors"
          >
              <ArrowLeft size={20} />
          </button>
          <span 
            className="font-bold text-sm opacity-0 transition-opacity duration-300"
            style={{ opacity: scrollOpacity }}
          >
            {name}
          </span>
          <div className="flex items-center gap-2">
            <button 
                onClick={() => window.location.reload()}
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-colors"
                title="Restart App"
            >
                <RotateCcw size={16} />
            </button>
            <button 
                onClick={handleLogout}
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-colors"
                title="Log Out"
            >
                <LogOut size={16} />
            </button>
          </div>
      </div>

      <motion.div 
        className="max-w-3xl mx-auto px-6 flex flex-col gap-8 -mt-2"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >

          {/* Hero Profile Section */}
          <motion.div 
            variants={heroVariants}
            className="flex flex-col items-center gap-6"
          >
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="relative w-48 h-48 md:w-56 md:h-56 rounded-full shadow-[0_8px_40px_rgba(0,0,0,0.5)] group cursor-pointer"
              >
                 {imagePreview ? (
                    <img src={imagePreview} alt="Profile" className="w-full h-full object-cover rounded-full" />
                 ) : (
                    <div className="w-full h-full rounded-full bg-[#282828] flex items-center justify-center text-6xl font-bold text-white/20">
                        {name.charAt(0).toUpperCase()}
                    </div>
                 )}

                 <div className="absolute inset-0 bg-black/50 rounded-full flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-[2px]">
                     <Camera size={32} className="text-white mb-2" />
                     <span className="text-xs font-bold uppercase tracking-widest">Edit Photo</span>
                 </div>
                 <motion.div 
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ delay: 0.5, type: "spring" }}
                    className="absolute bottom-2 right-4 bg-[#1DB954] text-black p-2 rounded-full border-4 border-[#121212]"
                 >
                    <Cloud size={16} />
                 </motion.div>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageChange} />

              <div className="flex flex-col items-center gap-2 w-full">
                  <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="bg-transparent text-center text-4xl md:text-5xl font-black text-white outline-none border-b border-transparent focus:border-white/20 pb-1 w-full max-w-md transition-all placeholder-white/20"
                    placeholder="Name"
                  />
                  <motion.div 
                    variants={itemVariants}
                    className="flex items-center gap-6 text-sm font-bold text-white/70 mt-2"
                  >
                      <div className="flex flex-col items-center">
                          <span className="text-white">12</span>
                          <span className="text-[10px] uppercase tracking-wider">Playlists</span>
                      </div>
                      <div className="flex flex-col items-center">
                          <span className="text-white">148</span>
                          <span className="text-[10px] uppercase tracking-wider">Followers</span>
                      </div>
                      <div className="flex flex-col items-center">
                          <span className="text-white">23</span>
                          <span className="text-[10px] uppercase tracking-wider">Following</span>
                      </div>
                  </motion.div>
              </div>
          </motion.div>

          <form onSubmit={handleSave} className="flex flex-col gap-6 mt-4">

              {/* Account Card */}
              <motion.div variants={itemVariants} className="bg-[#181818] p-5 rounded-lg">
                   <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                      <Shield size={20} className="text-[#1DB954]"/> Account
                   </h3>
                   <div className="flex items-center gap-4 text-sm">
                      <div className="p-3 bg-[#2A2A2A] rounded-full text-[#B3B3B3]">
                          <Mail size={20} />
                      </div>
                      <div className="flex flex-col flex-1">
                          <span className="text-xs text-[#B3B3B3] font-bold uppercase tracking-wider">Email</span>
                          <span className="text-white/80 font-medium">{currentUser.email}</span>
                      </div>
                      <span className="px-3 py-1 bg-[#2A2A2A] rounded-full text-[10px] font-bold text-[#B3B3B3]">PRIVATE</span>
                   </div>
              </motion.div>

              {/* Taste Profile */}
              <motion.div 
                  variants={itemVariants}
                  onClick={() => navigate('/artists/select')}
                  className="bg-[#181818] p-5 rounded-lg cursor-pointer hover:bg-[#202020] transition-colors group"
              >
                   <div className="flex items-center justify-between mb-2">
                        <h3 className="text-lg font-bold flex items-center gap-2">
                            <Users size={20} className="text-[#1DB954]"/> Taste Profile
                        </h3>
                        <ChevronRight className="text-[#555] group-hover:text-white transition-colors" />
                   </div>
                   <p className="text-sm text-[#B3B3B3] mb-4">Manage the artists you follow to improve recommendations.</p>

                   <div className="flex items-center gap-2 overflow-hidden">
                       {favoriteArtists.slice(0, 5).map((artist, i) => (
                           <div key={artist.id} className="w-10 h-10 rounded-full bg-[#333] overflow-hidden border border-black relative" style={{ zIndex: 5 - i }}>
                               <img src={artist.image[0]?.url} className="w-full h-full object-cover" alt=""/>
                           </div>
                       ))}
                       {favoriteArtists.length > 5 && (
                           <div className="w-10 h-10 rounded-full bg-[#2A2A2A] flex items-center justify-center text-xs font-bold text-white border border-black z-0">
