export const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { loginUser } = usePlayerStore();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const user = await authService.login(email.toLowerCase().trim(), password);
      loginUser(user);
      navigate('/');
    } catch (err: any) {
      setError(err.message || 'Login failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
      setLoading(true);
      setError('');
      try {
          const user = await authService.loginWithGoogle();
          loginUser(user);
          navigate('/');
      } catch (err: any) {
          setError(err.message || 'Google Login failed.');
          setLoading(false);
      }
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-[#191919] to-black text-white flex flex-col p-8 overflow-hidden">

      {/* Top Bar - Independent Animation */}
      <motion.div 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5, ease: "easeOut" }}
        className="w-full flex justify-start mb-8 md:mb-12"
      >
           <img 
              src="https://storage.googleapis.com/pr-newsroom-wp/1/2018/11/Spotify_Logo_RGB_White.png" 
              alt="Spotify" 
              className="h-8 md:h-10 w-auto" 
           />
      </motion.div>

      <motion.div 
        className="flex-1 flex flex-col items-center justify-center max-w-[734px] mx-auto w-full"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
        exit="exit"
      >

        <div className="w-full max-w-[324px] sm:max-w-[400px] flex flex-col gap-6 md:gap-8">
            <motion.h1 variants={itemVariants} className="text-3xl md:text-5xl font-black tracking-tighter text-center mb-4">Log in to Spotify</motion.h1>

            {error && (
                <motion.div variants={itemVariants} className="bg-[#e91429] text-white p-3 rounded text-sm text-center flex items-center justify-center gap-2 font-medium">
                   <span>⚠️</span> {error}
                </motion.div>
            )}

            {/* Social Login Buttons */}
            <motion.div variants={itemVariants} className="flex flex-col gap-2.5">
                <motion.button 
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    onClick={handleGoogleLogin}
                    disabled={loading}
                    className="flex items-center justify-center gap-4 w-full bg-transparent border border-[#878787] hover:border-white text-white font-bold py-3 px-8 rounded-full transition-all relative group"
                >
                    <div className="absolute left-6"><GoogleIcon /></div>
                    <span>Continue with Google</span>
                </motion.button>

                <motion.button 
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    className="flex items-center justify-center gap-4 w-full bg-[#1877F2] border border-transparent hover:brightness-105 text-white font-bold py-3 px-8 rounded-full transition-all relative"
                >
                    <div className="absolute left-6"><FacebookIcon /></div>
                    <span>Continue with Facebook</span>
                </motion.button>

                <motion.button 
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    className="flex items-center justify-center gap-4 w-full bg-black border border-[#878787] hover:border-white text-white font-bold py-3 px-8 rounded-full transition-all relative"
                >
                    <div className="absolute left-6"><AppleIcon /></div>
                    <span>Continue with Apple</span>
                </motion.button>
            </motion.div>

            <motion.div variants={itemVariants} className="flex items-center gap-4 my-2">
                <div className="h-[1px] bg-[#292929] flex-1"></div>
                <span className="text-sm font-bold text-white">OR</span>
                <div className="h-[1px] bg-[#292929] flex-1"></div>
            </motion.div>

            {/* Email Form */}
            <motion.form variants={itemVariants} onSubmit={handleLogin} className="flex flex-col gap-4">

               <div className="flex flex-col gap-2">
                  <label className="text-sm font-bold text-white">Email or username</label>
                  <input 
                    type="email" 
                    required
                    className="bg-[#121212] border border-[#727272] rounded-[4px] px-3.5 py-3.5 text-white focus:outline-none focus:border-white focus:ring-1 focus:ring-white transition-colors placeholder-[#727272]"
                    placeholder="Email or username"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                  />
               </div>

               <div className="flex flex-col gap-2">
                  <label className="text-sm font-bold text-white">Password</label>
                  <input 
                    type="password" 
                    required
                    className="bg-[#121212] border border-[#727272] rounded-[4px] px-3.5 py-3.5 text-white focus:outline-none focus:border-white focus:ring-1 focus:ring-white transition-colors placeholder-[#727272]"
                    placeholder="Password"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                  />
               </div>

               <div className="flex items-center gap-3 mt-1">
                   <div className="relative flex items-center">
                       <input 
                         type="checkbox" 
                         id="remember"
                         checked={rememberMe}
                         onChange={(e) => setRememberMe(e.target.checked)}
                         className="peer h-4 w-4 appearance-none rounded-[2px] border border-[#727272] bg-[#121212] checked:bg-[#1DB954] checked:border-[#1DB954] transition-all cursor-pointer"
                       />
                       <svg className="absolute w-3 h-3 text-black pointer-events-none opacity-0 peer-checked:opacity-100 left-0.5" viewBox="0 0 14 14" fill="none">
                           <path d="M3 8L6 11L11 3.5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                       </svg>
                   </div>
                   <label htmlFor="remember" className="text-sm text-white cursor-pointer select-none">Remember me</label>
               </div>

               <motion.button 
                  type="submit" 
                  disabled={loading}
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  className="bg-[#1DB954] text-black font-bold text-base py-3.5 rounded-full mt-4 flex items-center justify-center uppercase tracking-widest shadow-lg hover:bg-[#1ed760] transition-colors"
               >
                  {loading ? <Loader2 size={20} className="animate-spin" /> : 'Log In'}
               </motion.button>
            </motion.form>

            <motion.div variants={itemVariants} className="flex flex-col items-center gap-4 mt-2">
                <a href="#" className="text-white font-bold underline hover:text-[#1DB954] text-sm transition-colors">Forgot your password?</a>

                <div className="w-full h-[1px] bg-[#292929] my-2"></div>

                <div className="flex items-center gap-2 text-[#B3B3B3] text-sm md:text-base">
                    Don't have an account? 
                    <Link to="/signup" className="text-white hover:text-[#1DB954] hover:underline font-bold transition-colors">Sign up for Spotify</Link>
                </div>
            </motion.div>

            <motion.button 
                variants={itemVariants}
                onClick={() => navigate('/')} 
                className="text-sm text-[#B3B3B3] hover:text-white flex items-center justify-center gap-1 mt-6 transition-colors"
            >
                 <ArrowLeft size={16} /> Back to Web Player
            </motion.button>
        </div>
      </motion.div>

      {/* Footer Legal (Visual Only) */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1, duration: 0.5 }}
        className="text-[10px] text-[#555] text-center w-full mt-8"
      >
          This site is protected by reCAPTCHA and the Google Privacy Policy and Terms of Service apply.
      </motion.div>
    </div>
  );
};

