import React from 'react';
import { Play } from 'lucide-react';
import { SearchResult } from '../types';
import { getImageUrl } from '../services/api';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

interface SongCardProps {
  item: SearchResult;
  onPlay?: () => void;
  subtitle?: string;
  round?: boolean;
}

export const SongCard: React.FC<SongCardProps> = ({ item, onPlay, subtitle, round = false }) => {
  const navigate = useNavigate();
  const imageUrl = getImageUrl(item.image);

  const handleClick = () => {
    if (item.type === 'album') {
      navigate(`/album/${item.id}`);
    } else if (item.type === 'artist') {
      navigate(`/artist/${item.id}`, { state: { artist: item } });
    } else if (item.type === 'song' && onPlay) {
      onPlay();
    }
  };

  const handlePlayClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onPlay) onPlay();
  };

  // Safe subtitle generation
  let safeSubtitle = subtitle;
  if (!safeSubtitle) {
      if (item.type === 'song') {
          safeSubtitle = item.artists?.primary?.[0]?.name || item.artists?.all?.[0]?.name || 'Artist';
      } else if (item.type === 'album') {
          safeSubtitle = `Album • ${item.artists?.primary?.[0]?.name || 'Artist'}`;
      } else if (item.type === 'artist') {
          safeSubtitle = 'Artist';
      } else if (item.type === 'playlist') {
          safeSubtitle = item.subtitle || 'Playlist';
      }
  }

  // Handle display title
  const displayTitle = item.type === 'playlist' ? item.title : item.name;

  return (
    <motion.div 
      whileHover={{ y: -4 }}
      whileTap={{ scale: 0.98 }}
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      transition={{ duration: 0.2, ease: "easeOut" }}
      onClick={handleClick}
      className="group relative flex flex-col gap-2 cursor-pointer w-[140px] md:w-[180px] shrink-0"
    >
      <div className={`relative w-full aspect-square shadow-sm ${round ? 'rounded-full' : 'rounded-[16px]'} overflow-hidden bg-gray-100`}>
        <img 
          src={imageUrl} 
          alt={displayTitle} 
          className="w-full h-full object-cover"
          loading="lazy"
        />
        {/* Play Button Overlay - White button for light mode */}
        {!round && item.type !== 'artist' && (
          <motion.button 
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            onClick={handlePlayClick}
            className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity duration-200 bg-white/90 backdrop-blur-sm text-black rounded-full p-3 shadow-lg flex items-center justify-center z-20"
          >
            <Play size={20} fill="black" className="ml-1" />
          </motion.button>
        )}
      </div>
      <div className="flex flex-col gap-0.5 min-h-[40px] px-1">
        <h3 className="text-textPrimary font-semibold truncate text-[14px] leading-tight group-hover:text-black">
          {displayTitle}
        </h3>
        <p className="text-textSecondary text-[13px] truncate">
          {safeSubtitle}
        </p>
      </div>
    </motion.div>
  );
};

import React, { useEffect, useState } from 'react';
import { api, getImageUrl } from '../services/api';
