// Skeleton Component
const SkeletonCard: React.FC<{ round?: boolean }> = ({ round = false }) => (
  <div className="w-[140px] md:w-[180px] shrink-0 flex flex-col gap-3">
    <div className={`w-full aspect-square bg-gray-200 animate-pulse ${round ? 'rounded-full' : 'rounded-[16px]'}`}></div>
    <div className="flex flex-col gap-2">
      <div className="h-4 bg-gray-200 rounded w-3/4 animate-pulse"></div>
      <div className="h-3 bg-gray-200 rounded w-1/2 animate-pulse"></div>
    </div>
  </div>
);

export const Home: React.FC = () => {
  const [daylist, setDaylist] = useState<Song[]>([]);
  const [recent, setRecent] = useState<(Song | Album)[]>([]); 
  const { history, playSong, currentUser, isOfflineMode, downloadedSongIds, likedSongs } = usePlayerStore();
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'Songs' | 'Albums' | 'Podcasts'>('Songs');

  useEffect(() => {
    // Only fetch if online
    if (isOfflineMode) {
        setIsLoading(false);
        const offlineSongs = likedSongs.filter(s => downloadedSongIds.includes(s.id));
        setDaylist(offlineSongs);
        return;
    }

    const fetchData = async () => {
      setIsLoading(true);
      const hour = new Date().getHours();
      let query = 'Top Hits 2024';
      if (hour >= 5 && hour < 12) query = 'Morning Acoustic';
      else if (hour >= 12 && hour < 17) query = 'Upbeat Pop';
      else query = 'Late Night Vibes';

      try {
        const songs = await api.searchSongs(query);
        await new Promise(r => setTimeout(r, 400));
        setDaylist(songs);
      } catch (e) {
        console.error(e);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [isOfflineMode]);

  useEffect(() => {
    if (history.length > 0) {
      setRecent(history.slice(0, 6));
    } else if (!isOfflineMode) {
       Promise.all([
         api.searchSongs("The Weeknd"),
         api.searchAlbums("Starboy"),
         api.searchSongs("Taylor Swift"),
         api.searchAlbums("1989"),
       ]).then(([songs, albums, songs2, albums2]) => {
          setRecent([...songs.slice(0,1), ...albums.slice(0,1), ...songs2.slice(0,1), ...albums2.slice(0,1)]);
       });
    }
  }, [history, isOfflineMode]);

  const handleProfileClick = () => {
    if (currentUser) {
        navigate('/profile');
    } else {
        navigate('/login');
    }
  };

  const TabButton = ({ label }: { label: 'Songs' | 'Albums' | 'Podcasts' }) => {
      const isActive = activeTab === label;
      return (
        <button 
            onClick={() => setActiveTab(label)}
            className={`relative px-6 py-2.5 rounded-full text-sm font-semibold transition-colors duration-300 flex items-center gap-2 border ${isActive ? 'bg-[#E0E7FF] text-[#1e1b4b] border-[#E0E7FF]' : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'}`}
        >
            {isActive && <Check size={16} className="text-[#1e1b4b]" strokeWidth={3} />}
            {label}
        </button>
      );
  };

  const SectionTitle = ({ title }: { title: string }) => (
      <h2 className="text-[22px] font-semibold mb-4 text-textPrimary px-4 tracking-tight">{title}</h2>
  );

  return (
    <div className="flex flex-col gap-6 min-h-full pb-36 relative bg-white">

      {/* Google-Style Header */}
      <div className="pt-8 px-4 flex flex-col gap-6">
         {/* Top Bar (Avatar & Greeting) */}
         <div className="flex items-center justify-between">
             <h1 className="text-4xl font-bold text-textPrimary tracking-tight">Good Morning</h1>
             {/* Profile Icon */}
             <motion.div 
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={handleProfileClick}
                className="w-10 h-10 rounded-full bg-gray-200 flex items-center justify-center text-gray-600 shrink-0 cursor-pointer overflow-hidden"
             >
                 {currentUser && currentUser.image ? (
                     <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                     <UserCircle size={28} />
                 )}
             </motion.div>
         </div>

         {/* Pill Tabs */}
         <div className="flex items-center gap-3 overflow-x-auto no-scrollbar pb-1">
             <TabButton label="Songs" />
             <TabButton label="Albums" />
             <TabButton label="Podcasts" />
         </div>
      </div>

      {/* Content Area */}
      <div className="flex flex-col gap-8 mt-2">

          {/* Section 1: Recently Played */}
          <motion.section 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, ease: "easeOut" }}
          >
            <SectionTitle title="Recently Played" />
            <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
                {!isOfflineMode && isLoading ? (
                    Array(4).fill(0).map((_, i) => <SkeletonCard key={i} />)
                ) : recent.length > 0 ? (
                    recent.map((item, i) => (
                        <div key={i} className="snap-start">
                             <SongCard 
                                item={item} 
                                onPlay={() => item.type === 'song' && playSong(item as Song, [item as Song])} 
                             />
                        </div>
                    ))
                ) : (
                    <div className="text-gray-400 text-sm px-4">Nothing played recently.</div>
                )}
            </div>
          </motion.section>

          {/* Section 2: New Releases / Made For You */}
          <motion.section 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1, ease: "easeOut" }}
          >
            <SectionTitle title={isOfflineMode ? "Downloaded Music" : "New Releases"} />
            <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
                {isLoading && !isOfflineMode ? (
                     Array(6).fill(0).map((_, i) => <SkeletonCard key={i} />)
                ) : daylist.length > 0 ? (
                     daylist.map((item, i) => (
                        <div key={i} className="snap-start">
                            <SongCard item={item} onPlay={() => playSong(item, daylist)} />
                        </div>
                     ))
                ) : (
                    <div className="text-gray-400 px-4 text-sm">
                        {isOfflineMode ? "No downloaded music available." : "No recommendations yet."}
                    </div>
                )}
            </div>
          </motion.section>

          {/* Section 3: Recommended / Favorites */}
          {!isOfflineMode && (
              <motion.section 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: 0.2, ease: "easeOut" }}
              >
                  <SectionTitle title="Recommended for You" />
                  <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
                      {isLoading ? (
                          Array(6).fill(0).map((_, i) => <SkeletonCard key={i} />)
                      ) : (
                          daylist.slice().reverse().map((item, i) => (
                              <div key={i} className="snap-start">
                                  <SongCard item={item} onPlay={() => playSong(item, daylist)} />
                              </div>
                          ))
                      )}
                  </div>
              </motion.section>
          )}

      </div>
    </div>
  );
};

