import React, { useEffect, useState, useRef } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, Heart, Loader2, Shuffle, Repeat, CheckCircle2, PlusCircle, Sparkles } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const transitionSpec = {
  type: "tween",
  ease: [0.32, 0.72, 0, 1],
  duration: 0.4
};

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    shuffleMode,
    toggleShuffle,
    downloadedSongIds,
    duration, 
    audioElement,
    seek
  } = usePlayerStore();

  const navigate = useNavigate();

  const [dominantColor, setDominantColor] = useState<string>('#ffffff');

  const isDragging = useRef(false);
  const isSeeking = useRef(false); 
  const seekBarRef = useRef<HTMLDivElement>(null);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const fullProgressRef = useRef<HTMLDivElement>(null);
  const fullThumbRef = useRef<HTMLDivElement>(null);
  const fullTimeRef = useRef<HTMLSpanElement>(null);
  const miniProgressRef = useRef<HTMLDivElement>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const safeDuration = duration > 0 ? duration : 1;
  const isInteractive = duration > 0;

  useEffect(() => {
    let rafId: number;

    const updateUI = () => {
        if (isDragging.current || isSeeking.current) {
            if (isPlaying) rafId = requestAnimationFrame(updateUI);
            return;
        }

        if (!audioElement) return;

        const time = audioElement.currentTime;
        const percent = (time / safeDuration) * 100;

        if (fullProgressRef.current) fullProgressRef.current.style.width = `${percent}%`;
        if (fullThumbRef.current) fullThumbRef.current.style.left = `calc(${percent}% - 6px)`;
        if (fullTimeRef.current) fullTimeRef.current.innerText = formatTime(time);

        if (miniProgressRef.current) miniProgressRef.current.style.width = `${percent}%`;

        if (isPlaying) {
            rafId = requestAnimationFrame(updateUI);
        }
    };

    if (isPlaying) {
        rafId = requestAnimationFrame(updateUI);
    } else if (audioElement) {
        updateUI();
    }

    return () => {
        if (rafId) cancelAnimationFrame(rafId);
    };
  }, [isPlaying, audioElement, safeDuration, isFullScreen]);

  // Extract light dominant color for background if desired, or keep white/gray
  useEffect(() => {
    if (!currentSong) return;
    // For light mode, we might just stick to white/off-white for clean look
    setDominantColor('#F9FAFB'); 
  }, [currentSong?.id]);


  const calculateProgress = (clientX: number) => {
      if (!seekBarRef.current) return 0;
      const rect = seekBarRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
      return x / rect.width;
  };

  const updateVisualsFromInteraction = (percent: number) => {
      const time = percent * safeDuration;
      if (fullProgressRef.current) fullProgressRef.current.style.width = `${percent * 100}%`;
      if (fullThumbRef.current) fullThumbRef.current.style.left = `calc(${percent * 100}% - 6px)`;
      if (fullTimeRef.current) fullTimeRef.current.innerText = formatTime(time);
  };

  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!isInteractive) return;
      e.stopPropagation();
      e.preventDefault();
      isDragging.current = true;
      e.currentTarget.setPointerCapture(e.pointerId);
      const percent = calculateProgress(e.clientX);
      updateVisualsFromInteraction(percent);
  };

  const handlePointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!isDragging.current) return;
      e.stopPropagation();
      e.preventDefault();
      const percent = calculateProgress(e.clientX);
      updateVisualsFromInteraction(percent);
  };

  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!isDragging.current) return;
      e.stopPropagation();
      isDragging.current = false;
      isSeeking.current = true;
      const percent = calculateProgress(e.clientX);
      const time = percent * safeDuration;
      if (!isNaN(time) && isFinite(time)) seek(time);
      e.currentTarget.releasePointerCapture(e.pointerId);
      setTimeout(() => { isSeeking.current = false; }, 500);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if ((e.target as HTMLElement).closest('.slider-container')) return;
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong(); else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX)) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;
  const imageUrl = getImageUrl(currentSong.image);

  return (
    <>
        <AnimatePresence mode="popLayout">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={transitionSpec}
                    className="fixed inset-0 z-[200] flex flex-col bg-white isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                    style={{ transform: 'translateZ(0)' }}
                >
                    {/* Background Gradient */}
                    <motion.div 
                        className="absolute inset-0 z-[-1]" 
                        animate={{ backgroundColor: dominantColor }}
                        style={{ background: `linear-gradient(to bottom, #F3F4F6, #FFFFFF)` }} 
                    />

                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-8 md:pb-12 text-gray-900">

                        {/* Header */}
                        <div className="flex items-center justify-between h-14 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-gray-100 shrink-0"><ChevronDown size={28} className="text-gray-900" /></button>
                            <span className="text-[12px] font-bold tracking-widest uppercase text-gray-500">Now Playing</span>
                            <div className="w-10"></div>
                        </div>

                        {/* Art */}
                        <div className="flex-1 flex flex-col justify-center items-center min-h-0 py-4 md:py-8">
                            <div className="relative w-full aspect-square max-h-full max-w-[340px] shadow-2xl rounded-3xl overflow-hidden bg-gray-100 ring-1 ring-black/5">
                                <img src={imageUrl} alt="Cover" className="w-full h-full object-cover" />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col shrink-0 gap-6">

                            {/* Title Row */}
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-gray-900 truncate leading-tight">{currentSong.name}</h2>
                                    <p className="text-lg text-gray-500 truncate">{currentSong.artists?.primary?.[0]?.name}</p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0 p-1 rounded-full hover:bg-gray-100 transition-colors">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-white" /> : <PlusCircle size={28} className="text-gray-400" />}
                                </button>
                            </div>

                            {/* Scrubber */}
                            <div className="flex flex-col gap-2 pt-2 slider-container">
                                <div 
                                    ref={seekBarRef}
                                    className="relative h-4 w-full flex items-center cursor-pointer touch-none group"
                                    onPointerDown={handlePointerDown}
                                    onPointerMove={handlePointerMove}
                                    onPointerUp={handlePointerUp}
                                    onPointerCancel={handlePointerUp}
                                    style={{ touchAction: 'none' }} 
                                >
                                     <div className="absolute left-0 right-0 h-1.5 bg-gray-200 rounded-full overflow-hidden pointer-events-none group-hover:h-2 transition-all">
                                         <div ref={fullProgressRef} className="h-full bg-gray-900 rounded-full" style={{ width: '0%' }} />
                                     </div>
                                     <div ref={fullThumbRef} className="absolute h-4 w-4 bg-gray-900 rounded-full shadow-md z-10 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity ring-2 ring-white" style={{ left: '-6px' }} />
                                </div>
                                <div className="flex justify-between text-[11px] text-gray-500 font-mono font-medium pointer-events-none">
                                    <span ref={fullTimeRef}>0:00</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Main Controls */}
                            <div className="flex items-center justify-between px-2 mb-4">
                                <button 
                                    onClick={toggleShuffle} 
                                    className={`shrink-0 relative group p-2 rounded-full transition-colors ${shuffleMode !== 'off' ? 'text-[#1DB954]' : 'text-gray-400 hover:text-gray-900'}`}
                                >
                                    <Shuffle size={20} />
                                    {shuffleMode === 'smart' && (
                                        <div className="absolute -top-1 -right-1">
                                            <Sparkles size={8} fill="#1DB954" className="text-[#1DB954]" />
