                                </button>
                                <button onClick={prevSong} className="shrink-0 p-2 hover:bg-gray-100 rounded-full transition-colors"><SkipBack size={32} className="text-gray-900" fill="currentColor" /></button>
                                <button 
                                    onClick={togglePlay} 
                                    className="w-16 h-16 bg-gray-900 rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0 shadow-xl"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-white" /> : isPlaying ? <Pause size={32} fill="white" className="text-white" /> : <Play size={32} fill="white" className="ml-1 text-white" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0 p-2 hover:bg-gray-100 rounded-full transition-colors"><SkipForward size={32} className="text-gray-900" fill="currentColor" /></button>
                                <button className="text-gray-400 shrink-0 p-2 hover:text-gray-900 transition-colors"><Repeat size={20} /></button>
