                    className="fixed bottom-24 md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[64px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                    style={{ transform: 'translateZ(0)' }}
                >
                    {/* Mini Player Card */}
                    <motion.div 
                        className="absolute inset-0 z-[-1] rounded-xl shadow-[0_8px_24px_rgba(0,0,0,0.12)] overflow-hidden bg-white border border-gray-100" 
                    />

                    <div className="flex items-center h-full px-3 gap-3">
                        <div className="h-10 w-10 shrink-0 rounded-lg overflow-hidden bg-gray-200">
