const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const location = useLocation();
  const { isOfflineMode } = usePlayerStore();
  const isFullScreenPage = ['/premium', '/login', '/signup', '/artists/select'].includes(location.pathname);
  const mainRef = useRef<HTMLElement>(null);

  useEffect(() => {
    if (mainRef.current) {
      mainRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [location.pathname]);

  return (
    <div className="flex h-[100dvh] w-screen bg-background text-textPrimary overflow-hidden relative">
      <AudioController />

      {!isFullScreenPage && <Sidebar />}

      <AnimatePresence>
          {isOfflineMode && !isFullScreenPage && (
              <motion.div 
                initial={{ y: -50, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: -50, opacity: 0 }}
                transition={{ type: "tween", duration: 0.3 }}
                className="absolute top-0 left-0 right-0 z-[100] bg-surfaceVariant/90 backdrop-blur-md flex items-center justify-center p-1 border-b border-outline/10"
