      <main 
        ref={mainRef}
        className={`flex-1 relative overflow-y-auto bg-background md:rounded-2xl md:my-2 md:mx-0 md:mr-2 no-scrollbar overscroll-none ${isFullScreenPage ? 'z-50 !m-0 !rounded-none' : ''}`}
      >
        {children}
