export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const [isLoading, setIsLoading] = useState(false);

  const { playSong, likedSongs, toggleLike, musicSource } = usePlayerStore();
  const navigate = useNavigate();
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    if (abortControllerRef.current) {
        abortControllerRef.current.abort();
    }

    if (!query.trim()) {
        setResults({ songs: [], albums: [], artists: [] });
        setIsLoading(false);
        return;
    }

    setIsLoading(true);

    const timer = setTimeout(async () => {
        abortControllerRef.current = new AbortController();
        try {
           const [songs, albums, artists] = await Promise.all([
              api.searchSongs(query, musicSource),
              api.searchAlbums(query),
              api.searchArtists(query)
           ]);

           if (!abortControllerRef.current?.signal.aborted) {
               setResults({ songs, albums, artists });
           }
        } catch (e: any) {
            if (e.name !== 'AbortError') {
                console.error(e);
            }
        } finally {
            if (!abortControllerRef.current?.signal.aborted) {
                setIsLoading(false);
            }
        }
    }, 300);

    return () => clearTimeout(timer);
  }, [query, musicSource]);

  const clearSearch = () => {
    setQuery('');
    setResults({ songs: [], albums: [], artists: [] });
    setIsLoading(false);
  };

  const handleResultClick = (item: SearchResult) => {
      if (item.type === 'artist') {
          navigate(`/artist/${item.id}`, { state: { artist: item } });
      } else if (item.type === 'album') {
          navigate(`/album/${item.id}`);
      } else if (item.type === 'song') {
          playSong(item as Song, results.songs.length > 0 ? results.songs : [item as Song]);
      }
  };

  const handleKeywordSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && query.trim()) {
          (e.target as HTMLInputElement).blur();
      }
  };

  const ResultSkeleton = () => (
      <div className="flex items-center gap-3 px-4 py-3 animate-pulse">
          <div className="w-14 h-14 bg-surfaceVariant rounded-md shrink-0"></div>
          <div className="flex-1 space-y-2 py-1">
              <div className="h-4 bg-surfaceVariant rounded w-1/3"></div>
              <div className="h-3 bg-surfaceVariant/50 rounded w-1/4"></div>
          </div>
      </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 bg-background">

      <div className="sticky top-0 bg-background z-30 px-4 py-4 border-b border-transparent transition-colors duration-300">
         <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="md:hidden text-textPrimary hover:bg-surfaceVariant p-2 rounded-full">
                 <ArrowLeft size={24} />
             </button>
             <div className="relative flex-1">
                 <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-textSecondary" size={24} />
                 <input 
                    type="text" 
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={handleKeywordSearch}
                    placeholder="What do you want to listen to?" 
                    className="w-full bg-surfaceVariant text-textPrimary pl-12 pr-12 py-3.5 rounded-full font-medium text-base placeholder-textSecondary/70 focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all shadow-sm border border-transparent"
                    autoFocus={false}
                 />
                 {query && (
                     <button onClick={clearSearch} className="absolute right-4 top-1/2 -translate-y-1/2 text-textPrimary hover:bg-black/5 p-1 rounded-full">
                         <X size={20} />
                     </button>
                 )}
             </div>
         </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pt-2">

          {!query && (
              <div className="px-4 pb-8 animate-in fade-in duration-500">
                  <h2 className="text-textPrimary font-bold text-xl mb-4 mt-2">Browse all</h2>
                  <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                      {BROWSE_CATEGORIES.map((cat) => (
                          <motion.div 
                              key={cat.title}
                              whileHover={{ scale: 1.02 }}
                              whileTap={{ scale: 0.98 }}
                              className={`${cat.color} h-[100px] md:h-[120px] rounded-[16px] p-4 relative overflow-hidden cursor-pointer shadow-md`}
                              onClick={() => setQuery(cat.title)}
                          >
                              <span className="text-white font-bold text-lg md:text-xl absolute top-4 left-4 max-w-[70%] leading-tight">{cat.title}</span>
                              <div className="absolute -bottom-2 -right-4 w-20 h-20 bg-white/20 rotate-[25deg] rounded-md shadow-sm transform translate-x-2 translate-y-2"></div>
                          </motion.div>
                      ))}
                  </div>
              </div>
          )}

          {query && !isLoading && results.songs.length === 0 && results.artists.length === 0 && (
              <div className="px-4 text-center py-20 text-textSecondary">
                  <p className="text-lg">No results found for "{query}"</p>
                  <p className="text-sm mt-2">Try searching for artists, songs, or albums.</p>
              </div>
          )}

          {isLoading && (
              <div className="flex flex-col gap-2 pt-2">
                  <ResultSkeleton />
                  <ResultSkeleton />
                  <ResultSkeleton />
                  <ResultSkeleton />
                  <ResultSkeleton />
              </div>
          )}

          {(results.songs.length > 0 || results.artists.length > 0 || results.albums.length > 0) && (
              <motion.div 
                 variants={containerVariants}
                 initial="hidden"
                 animate="visible"
                 className="flex flex-col gap-8 pb-8"
              >
                  {results.artists.length > 0 && (
                      <div className="px-4">
                          <h2 className="text-textPrimary font-bold text-xl mb-4">Top Result</h2>
                          <motion.div 
                              variants={itemVariants}
                              onClick={() => handleResultClick(results.artists[0])}
                              className="bg-surface hover:bg-surfaceVariant p-5 rounded-[24px] flex flex-col items-start gap-4 transition-colors cursor-pointer group shadow-sm border border-outline/10"
                          >
                              <img src={getImageUrl(results.artists[0].image)} className="w-24 h-24 rounded-full shadow-md object-cover group-hover:scale-105 transition-transform" alt=""/>
                              <div className="flex flex-col gap-1">
                                  <h3 className="text-textPrimary font-bold text-2xl md:text-3xl">{results.artists[0].name}</h3>
                                  <div className="flex items-center gap-2">
                                      <span className="bg-pillActive text-pillText px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">Artist</span>
                                  </div>
                              </div>
                          </motion.div>
                      </div>
                  )}

                  {results.songs.length > 0 && (
                      <div className="px-4">
                          <h2 className="text-textPrimary font-bold text-xl mb-2">Songs</h2>
                          <div className="flex flex-col gap-1">
                              {results.songs.map((song) => {
                                  const isLiked = likedSongs.some(s => s.id === song.id);
                                  return (
                                    <motion.div 
                                        key={song.id} 
                                        variants={itemVariants}
                                        onClick={() => handleResultClick(song)}
                                        className="group flex items-center gap-4 p-3 rounded-[12px] hover:bg-surfaceVariant/50 cursor-pointer transition-colors"
                                    >
                                        <div className="relative w-14 h-14 shrink-0">
                                            <img src={getImageUrl(song.image)} alt={song.name} className="w-full h-full object-cover rounded-md shadow-sm group-hover:opacity-80 transition-opacity" />
                                            <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                                <Play size={24} fill="white" className="text-white drop-shadow-md" />
                                            </div>
                                        </div>
                                        <div className="flex flex-col flex-1 min-w-0">
                                            <span className={`font-bold text-[15px] truncate ${isLiked ? 'text-primary' : 'text-textPrimary'}`}>{song.name}</span>
                                            <span className="text-sm text-textSecondary truncate">{song.artists.primary[0]?.name}</span>
                                        </div>
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                            className="p-2 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            {isLiked ? <CheckCircle2 size={24} className="text-accent" /> : <PlusCircle size={24} className="text-textSecondary hover:text-textPrimary" />}
                                        </button>
                                        <div className="text-xs text-textSecondary font-mono w-10 text-right">
                                            {(parseInt(song.duration) / 60).toFixed(0)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                                        </div>
                                    </motion.div>
                                  );
                              })}
                          </div>
                      </div>
                  )}

                  {results.artists.length > 0 && (
                       <div className="px-4">
                           <h2 className="text-textPrimary font-bold text-xl mb-4">Artists</h2>
                           <div className="flex overflow-x-auto gap-4 no-scrollbar pb-4">
                               {results.artists.map(artist => (
                                   <motion.div 
                                       key={artist.id}
                                       variants={itemVariants}
                                       onClick={() => handleResultClick(artist)}
                                       className="flex flex-col items-center gap-3 w-[140px] shrink-0 cursor-pointer group"
                                   >
                                       <div className="w-[140px] h-[140px] rounded-full overflow-hidden shadow-md">
                                           <img src={getImageUrl(artist.image)} alt={artist.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                                       </div>
                                       <span className="text-textPrimary font-bold text-center text-sm truncate w-full group-hover:underline">{artist.name}</span>
                                       <span className="text-textSecondary text-xs">Artist</span>
                                   </motion.div>
                               ))}
                           </div>
                       </div>
                  )}

                  {results.albums.length > 0 && (
                       <div className="px-4">
                           <h2 className="text-textPrimary font-bold text-xl mb-4">Albums</h2>
                           <div className="flex overflow-x-auto gap-4 no-scrollbar pb-4">
                               {results.albums.map(album => (
                                   <motion.div 
                                       key={album.id}
                                       variants={itemVariants}
                                       onClick={() => handleResultClick(album)}
                                       className="flex flex-col gap-3 w-[160px] shrink-0 cursor-pointer group"
                                   >
                                       <div className="w-[160px] h-[160px] rounded-[16px] overflow-hidden shadow-md relative bg-surfaceVariant">
                                           <img src={getImageUrl(album.image)} alt={album.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                                       </div>
                                       <div className="flex flex-col gap-0.5">
                                            <span className="text-textPrimary font-bold text-sm truncate w-full group-hover:underline">{album.name}</span>
                                            <span className="text-textSecondary text-xs truncate">{album.year} • Album</span>
                                       </div>
                                   </motion.div>
                               ))}
                           </div>
                       </div>
                  )}

              </motion.div>
          )}
