            className="mb-4 bg-surfaceVariant rounded-[16px] p-4 flex items-center gap-3"
         >
             <div className="bg-white p-2 rounded-full shadow-sm"><WifiOff size={20} className="text-textSecondary" /></div>
             <div className="flex flex-col">
                 <span className="text-sm font-bold text-textPrimary">You're offline</span>
                 <span className="text-xs text-textSecondary">Showing only downloaded music.</span>
