      <div className="flex items-center gap-2 mb-6 overflow-x-auto no-scrollbar">
          {!isOfflineMode && <FilterChip label="All" />}
          {!isOfflineMode && <FilterChip label="Playlists" />}
          {!isOfflineMode && <FilterChip label="Artists" />}
          <FilterChip label="Downloaded" />
      </div>

      <div className="flex items-center justify-between mb-4 px-1">
          <div className="flex items-center gap-1 text-textSecondary text-sm">
              <ArrowUpDown size={14} />
              <span className="font-medium">Recents</span>
          </div>
          <div className="p-1">
              <div className="grid grid-cols-2 gap-0.5 opacity-50">
                  <div className="w-1.5 h-1.5 bg-textSecondary rounded-[1px]"></div>
                  <div className="w-1.5 h-1.5 bg-textSecondary rounded-[1px]"></div>
                  <div className="w-1.5 h-1.5 bg-textSecondary rounded-[1px]"></div>
                  <div className="w-1.5 h-1.5 bg-textSecondary rounded-[1px]"></div>
              </div>
          </div>
      </div>

      <motion.div 
        className="flex flex-col gap-2"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >

          {(!isOfflineMode || downloadedLikedSongsCount > 0) && (
              <motion.div 
                variants={itemVariants}
                onClick={() => navigate('/liked')}
                className="flex items-center gap-4 p-2 hover:bg-surfaceVariant/50 rounded-[16px] cursor-pointer active:scale-[0.99] transition-all group"
              >
                  <div className="w-[56px] h-[56px] bg-gradient-to-br from-[#450af5] to-[#c4efd9] flex items-center justify-center shrink-0 rounded-[12px] shadow-sm">
                     <Heart size={24} fill="white" className="text-white" />
                  </div>
                  <div className="flex flex-col flex-1 min-w-0">
                      <span className="text-textPrimary font-bold text-[16px] truncate">Liked Songs</span>
                      <div className="flex items-center gap-1.5 text-textSecondary text-sm font-medium">
                           <Pin size={12} fill="#1DB954" className="text-[#1DB954] rotate-45" />
                           <span>Playlist • {isOfflineMode ? downloadedLikedSongsCount : likedSongs.length} songs</span>
                           {isOfflineMode && <CheckCircle2 size={12} className="text-[#1DB954]" />}
                      </div>
                  </div>
              </motion.div>
          )}

          {filteredPlaylists.map(playlist => (
             <motion.div 
                key={playlist.id}
                variants={itemVariants}
                onClick={() => navigate(`/playlist/${playlist.id}`)}
                className="flex items-center gap-4 p-2 hover:bg-surfaceVariant/50 rounded-[16px] cursor-pointer active:scale-[0.99] transition-all group"
             >
                <div className="w-[56px] h-[56px] bg-surfaceVariant shrink-0 rounded-[12px] overflow-hidden shadow-sm border border-outline/5">
                    {playlist.image && playlist.image[0] ? (
                        <img src={getImageUrl(playlist.image)} alt={playlist.title} className="w-full h-full object-cover" />
                    ) : (
                        <div className="w-full h-full flex items-center justify-center bg-surfaceVariant">
                            <Music size={24} className="text-textSecondary/40" />
                        </div>
                    )}
                </div>
                <div className="flex flex-col flex-1 min-w-0">
                    <span className="text-textPrimary font-bold text-[16px] truncate">{playlist.title}</span>
                    <div className="flex items-center gap-1 text-textSecondary text-sm font-medium truncate">
                        <span>Playlist • {playlist.subtitle}</span>
                        {isOfflineMode && <CheckCircle2 size={12} className="text-[#1DB954]" />}
                    </div>
                </div>
             </motion.div>
          ))}

          {isOfflineMode && filteredPlaylists.length === 0 && downloadedLikedSongsCount === 0 && (
              <div className="text-center py-12 text-textSecondary">
                  <WifiOff size={40} className="mx-auto mb-4 opacity-50" />
                  <p className="font-bold text-lg">No downloaded content found.</p>
                  <p className="text-sm mt-2">Go online to download music.</p>
              </div>
          )}

      </motion.div>

      {isModalOpen && <CreatePlaylistModal onClose={() => setIsModalOpen(false)} />}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, Heart, Loader2, Shuffle, Repeat, CheckCircle2, PlusCircle, Sparkles } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const transitionSpec = {
  type: "tween",
  ease: [0.32, 0.72, 0, 1],
  duration: 0.4
};

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    shuffleMode,
    toggleShuffle,
    duration, 
    audioElement,
    seek
  } = usePlayerStore();

  const [dominantColor, setDominantColor] = useState<string>('#FEF7FF');
  const isDragging = useRef(false);
  const isSeeking = useRef(false); 
  const seekBarRef = useRef<HTMLDivElement>(null);
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const fullProgressRef = useRef<HTMLDivElement>(null);
  const fullThumbRef = useRef<HTMLDivElement>(null);
  const fullTimeRef = useRef<HTMLSpanElement>(null);
  const miniProgressRef = useRef<HTMLDivElement>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const safeDuration = duration > 0 ? duration : 1;
  const isInteractive = duration > 0;

  useEffect(() => {
    let rafId: number;
    const updateUI = () => {
        if (isDragging.current || isSeeking.current) {
            if (isPlaying) rafId = requestAnimationFrame(updateUI);
            return;
        }
        if (!audioElement) return;
        const time = audioElement.currentTime;
        const percent = (time / safeDuration) * 100;

        if (fullProgressRef.current) fullProgressRef.current.style.width = `${percent}%`;
        if (fullThumbRef.current) fullThumbRef.current.style.left = `calc(${percent}% - 6px)`;
        if (fullTimeRef.current) fullTimeRef.current.innerText = formatTime(time);
        if (miniProgressRef.current) miniProgressRef.current.style.width = `${percent}%`;

        if (isPlaying) rafId = requestAnimationFrame(updateUI);
    };
    if (isPlaying) rafId = requestAnimationFrame(updateUI);
    else if (audioElement) updateUI();
    return () => { if (rafId) cancelAnimationFrame(rafId); };
  }, [isPlaying, audioElement, safeDuration, isFullScreen]);

  // Keep background clean
  useEffect(() => {
    if (!currentSong) return;
    setDominantColor('#F3EDF7'); 
  }, [currentSong?.id]);

  const calculateProgress = (clientX: number) => {
      if (!seekBarRef.current) return 0;
      const rect = seekBarRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
      return x / rect.width;
  };

  const updateVisualsFromInteraction = (percent: number) => {
      const time = percent * safeDuration;
      if (fullProgressRef.current) fullProgressRef.current.style.width = `${percent * 100}%`;
      if (fullThumbRef.current) fullThumbRef.current.style.left = `calc(${percent * 100}% - 6px)`;
      if (fullTimeRef.current) fullTimeRef.current.innerText = formatTime(time);
  };

  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!isInteractive) return;
      e.stopPropagation(); e.preventDefault();
      isDragging.current = true;
      e.currentTarget.setPointerCapture(e.pointerId);
      const percent = calculateProgress(e.clientX);
      updateVisualsFromInteraction(percent);
  };

  const handlePointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!isDragging.current) return;
      e.stopPropagation(); e.preventDefault();
      const percent = calculateProgress(e.clientX);
      updateVisualsFromInteraction(percent);
  };

  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!isDragging.current) return;
      e.stopPropagation(); isDragging.current = false; isSeeking.current = true;
      const percent = calculateProgress(e.clientX);
      const time = percent * safeDuration;
      if (!isNaN(time) && isFinite(time)) seek(time);
      e.currentTarget.releasePointerCapture(e.pointerId);
      setTimeout(() => { isSeeking.current = false; }, 500);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if ((e.target as HTMLElement).closest('.slider-container')) return;
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const diffX = touchStart.x - e.changedTouches[0].clientX;
    const diffY = touchStart.y - e.changedTouches[0].clientY;
    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong(); else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX)) setFullScreen(false);
    setTouchStart(null);
  };

  if (!currentSong) return null;
  const imageUrl = getImageUrl(currentSong.image);

  return (
    <>
        <AnimatePresence mode="popLayout">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={transitionSpec}
                    className="fixed inset-0 z-[200] flex flex-col bg-background isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                    style={{ transform: 'translateZ(0)' }}
                >
                    <motion.div 
                        className="absolute inset-0 z-[-1]" 
                        animate={{ backgroundColor: dominantColor }}
                        style={{ background: `linear-gradient(to bottom, ${dominantColor}, #FEF7FF)` }} 
                    />

                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-8 md:pb-12 text-textPrimary">

                        <div className="flex items-center justify-between h-14 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-surfaceVariant shrink-0"><ChevronDown size={28} className="text-textPrimary" /></button>
                            <span className="text-[12px] font-bold tracking-widest uppercase text-textSecondary">Now Playing</span>
                            <div className="w-10"></div>
                        </div>

                        <div className="flex-1 flex flex-col justify-center items-center min-h-0 py-4 md:py-8">
                            <div className="relative w-full aspect-square max-h-full max-w-[340px] shadow-2xl rounded-3xl overflow-hidden bg-surfaceVariant ring-1 ring-black/5">
                                <img src={imageUrl} alt="Cover" className="w-full h-full object-cover" />
                            </div>
                        </div>

                        <div className="flex flex-col shrink-0 gap-6">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-textPrimary truncate leading-tight">{currentSong.name}</h2>
                                    <p className="text-lg text-textSecondary truncate">{currentSong.artists?.primary?.[0]?.name}</p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0 p-1 rounded-full hover:bg-surfaceVariant transition-colors">
                                    {isLiked ? <CheckCircle2 size={28} className="text-accent fill-white" /> : <PlusCircle size={28} className="text-textSecondary" />}
                                </button>
                            </div>

                            <div className="flex flex-col gap-2 pt-2 slider-container">
                                <div 
                                    ref={seekBarRef}
                                    className="relative h-4 w-full flex items-center cursor-pointer touch-none group"
                                    onPointerDown={handlePointerDown}
                                    onPointerMove={handlePointerMove}
                                    onPointerUp={handlePointerUp}
                                    onPointerCancel={handlePointerUp}
                                    style={{ touchAction: 'none' }} 
                                >
                                     <div className="absolute left-0 right-0 h-1.5 bg-surfaceVariant rounded-full overflow-hidden pointer-events-none group-hover:h-2 transition-all">
                                         <div ref={fullProgressRef} className="h-full bg-textPrimary rounded-full" style={{ width: '0%' }} />
                                     </div>
                                     <div ref={fullThumbRef} className="absolute h-4 w-4 bg-textPrimary rounded-full shadow-md z-10 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity ring-2 ring-white" style={{ left: '-6px' }} />
                                </div>
                                <div className="flex justify-between text-[11px] text-textSecondary font-mono font-medium pointer-events-none">
                                    <span ref={fullTimeRef}>0:00</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            <div className="flex items-center justify-between px-2 mb-4">
                                <button 
                                    onClick={toggleShuffle} 
                                    className={`shrink-0 relative group p-2 rounded-full transition-colors ${shuffleMode !== 'off' ? 'text-accent' : 'text-textSecondary hover:text-textPrimary'}`}
                                >
                                    <Shuffle size={20} />
                                    {shuffleMode === 'smart' && (
                                        <div className="absolute -top-1 -right-1">
                                            <Sparkles size={8} fill="#1DB954" className="text-accent" />
                                        </div>
                                    )}
                                </button>
                                <button onClick={prevSong} className="shrink-0 p-2 hover:bg-surfaceVariant rounded-full transition-colors"><SkipBack size={32} className="text-textPrimary" fill="currentColor" /></button>
                                <button 
                                    onClick={togglePlay} 
                                    className="w-16 h-16 bg-primary rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0 shadow-xl"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-white" /> : isPlaying ? <Pause size={32} fill="white" className="text-white" /> : <Play size={32} fill="white" className="ml-1 text-white" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0 p-2 hover:bg-surfaceVariant rounded-full transition-colors"><SkipForward size={32} className="text-textPrimary" fill="currentColor" /></button>
                                <button className="text-textSecondary shrink-0 p-2 hover:text-textPrimary transition-colors"><Repeat size={20} /></button>
                            </div>
                        </div>
                    </div>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: "100%", opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: "100%", opacity: 0 }}
                    transition={transitionSpec}
                    className="fixed bottom-24 md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[64px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                    style={{ transform: 'translateZ(0)' }}
                >
                    <motion.div 
                        className="absolute inset-0 z-[-1] rounded-2xl shadow-[0_8px_24px_rgba(0,0,0,0.08)] overflow-hidden bg-surfaceVariant border border-outline/5" 
                    />

                    <div className="flex items-center h-full px-3 gap-3">
                        <div className="h-10 w-10 shrink-0 rounded-lg overflow-hidden bg-surface">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        <div className="flex-1 min-w-0 pr-2 flex flex-col justify-center">
                            <div className="text-textPrimary font-bold text-sm truncate">{currentSong.name}</div>
                            <div className="text-textSecondary text-xs truncate">{currentSong.artists.primary[0]?.name}</div>
                        </div>

                        <div className="flex items-center gap-2 shrink-0">
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="p-2 text-textSecondary hover:text-accent">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-accent" : ""} />
                            </button>
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="p-2 text-textPrimary">
                                {isBuffering ? <Loader2 size={24} className="animate-spin text-textSecondary" /> : isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" />}
                            </button>
                        </div>
                    </div>
                    <div className="absolute bottom-0 left-3 right-3 h-[3px] bg-surface rounded-full overflow-hidden mb-1">
                        <div ref={miniProgressRef} className="h-full bg-primary rounded-full" style={{ width: '0%' }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    </>
  );
};

