import React, { useEffect, useState } from 'react';
import { api } from '../services/api';
import { Song, Album } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { UserCircle, Check } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { SongCard } from '../components/SongCard';
import { motion } from 'framer-motion';

const SkeletonCard: React.FC<{ round?: boolean }> = ({ round = false }) => (
  <div className="w-[140px] md:w-[180px] shrink-0 flex flex-col gap-3">
    <div className={`w-full aspect-square bg-surfaceVariant animate-pulse ${round ? 'rounded-full' : 'rounded-[16px]'}`}></div>
    <div className="flex flex-col gap-2">
      <div className="h-4 bg-surfaceVariant rounded w-3/4 animate-pulse"></div>
      <div className="h-3 bg-surfaceVariant rounded w-1/2 animate-pulse"></div>
    </div>
  </div>
);

export const Home: React.FC = () => {
  const [daylist, setDaylist] = useState<Song[]>([]);
  const [recent, setRecent] = useState<(Song | Album)[]>([]); 
  const { history, playSong, currentUser, isOfflineMode, downloadedSongIds, likedSongs } = usePlayerStore();
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'Songs' | 'Albums' | 'Podcasts'>('Songs');

  useEffect(() => {
    if (isOfflineMode) {
        setIsLoading(false);
        const offlineSongs = likedSongs.filter(s => downloadedSongIds.includes(s.id));
        setDaylist(offlineSongs);
        return;
    }

    const fetchData = async () => {
      setIsLoading(true);
      const hour = new Date().getHours();
      let query = 'Top Hits 2024';
      if (hour >= 5 && hour < 12) query = 'Morning Acoustic';
      else if (hour >= 12 && hour < 17) query = 'Upbeat Pop';
      else query = 'Late Night Vibes';

      try {
        const songs = await api.searchSongs(query);
        await new Promise(r => setTimeout(r, 400));
        setDaylist(songs);
      } catch (e) {
        console.error(e);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [isOfflineMode]);

  useEffect(() => {
    if (history.length > 0) {
      setRecent(history.slice(0, 6));
    } else if (!isOfflineMode) {
       Promise.all([
         api.searchSongs("The Weeknd"),
         api.searchAlbums("Starboy"),
         api.searchSongs("Taylor Swift"),
         api.searchAlbums("1989"),
       ]).then(([songs, albums, songs2, albums2]) => {
          setRecent([...songs.slice(0,1), ...albums.slice(0,1), ...songs2.slice(0,1), ...albums2.slice(0,1)]);
       });
    }
  }, [history, isOfflineMode]);

  const handleProfileClick = () => {
    if (currentUser) {
        navigate('/profile');
    } else {
        navigate('/login');
    }
  };

  const SectionTitle = ({ title }: { title: string }) => (
      <h2 className="text-[22px] font-semibold mb-4 text-textPrimary px-4 tracking-tight">{title}</h2>
  );

  return (
    <div className="flex flex-col gap-6 min-h-full pb-36 relative bg-[#FEF7FF]">

      {/* Header */}
      <div className="pt-8 px-4 flex flex-col gap-6">
         <div className="flex items-center justify-between">
             <h1 className="text-4xl font-bold text-[#1D1B20] tracking-tight">Good Morning</h1>
             <motion.div 
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={handleProfileClick}
                className="w-10 h-10 rounded-full bg-[#E7E0EC] flex items-center justify-center text-[#49454F] shrink-0 cursor-pointer overflow-hidden border border-[#79747E]/10"
             >
                 {currentUser && currentUser.image ? (
                     <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                     <UserCircle size={28} />
                 )}
             </motion.div>
         </div>

         {/* Segmented Button (Pills) Style */}
         <div className="flex items-center">
             <div className="inline-flex rounded-full border border-[#79747E] overflow-hidden">
                 {/* Songs Tab */}
                 <button 
                    onClick={() => setActiveTab('Songs')}
                    className={`px-6 py-2.5 text-sm font-medium flex items-center gap-2 transition-colors ${activeTab === 'Songs' ? 'bg-[#E8DEF8] text-[#1D192B]' : 'bg-transparent text-[#49454F] hover:bg-[#F3EDF7]'}`}
                 >
                    {activeTab === 'Songs' && <Check size={18} />}
                    Songs
                 </button>

                 <div className="w-[1px] bg-[#79747E]"></div>

                 {/* Albums Tab */}
                 <button 
                    onClick={() => setActiveTab('Albums')}
                    className={`px-6 py-2.5 text-sm font-medium flex items-center gap-2 transition-colors ${activeTab === 'Albums' ? 'bg-[#E8DEF8] text-[#1D192B]' : 'bg-transparent text-[#49454F] hover:bg-[#F3EDF7]'}`}
                 >
                    {activeTab === 'Albums' && <Check size={18} />}
                    Albums
                 </button>

                 <div className="w-[1px] bg-[#79747E]"></div>

                 {/* Podcasts Tab */}
                 <button 
                    onClick={() => setActiveTab('Podcasts')}
                    className={`px-6 py-2.5 text-sm font-medium flex items-center gap-2 transition-colors ${activeTab === 'Podcasts' ? 'bg-[#E8DEF8] text-[#1D192B]' : 'bg-transparent text-[#49454F] hover:bg-[#F3EDF7]'}`}
                 >
                    {activeTab === 'Podcasts' && <Check size={18} />}
                    Podcasts
                 </button>
             </div>
         </div>
      </div>

      {/* Content */}
      <div className="flex flex-col gap-8 mt-2">

          <motion.section 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, ease: "easeOut" }}
          >
            <SectionTitle title="Recently Played" />
            <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
                {!isOfflineMode && isLoading ? (
                    Array(4).fill(0).map((_, i) => <SkeletonCard key={i} />)
                ) : recent.length > 0 ? (
                    recent.map((item, i) => (
                        <div key={i} className="snap-start">
                             <SongCard 
                                item={item} 
                                onPlay={() => item.type === 'song' && playSong(item as Song, [item as Song])} 
                             />
                        </div>
                    ))
                ) : (
                    <div className="text-[#49454F] text-sm px-4">Nothing played recently.</div>
                )}
            </div>
          </motion.section>

          <motion.section 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1, ease: "easeOut" }}
          >
            <SectionTitle title={isOfflineMode ? "Downloaded Music" : "New Releases"} />
            <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
                {isLoading && !isOfflineMode ? (
                     Array(6).fill(0).map((_, i) => <SkeletonCard key={i} />)
                ) : daylist.length > 0 ? (
                     daylist.map((item, i) => (
                        <div key={i} className="snap-start">
                            <SongCard item={item} onPlay={() => playSong(item, daylist)} />
                        </div>
                     ))
                ) : (
                    <div className="text-[#49454F] px-4 text-sm">
                        {isOfflineMode ? "No downloaded music available." : "No recommendations yet."}
                    </div>
                )}
            </div>
          </motion.section>

          {!isOfflineMode && (
              <motion.section 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: 0.2, ease: "easeOut" }}
              >
                  <SectionTitle title="Recommended for You" />
                  <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
                      {isLoading ? (
                          Array(6).fill(0).map((_, i) => <SkeletonCard key={i} />)
                      ) : (
                          daylist.slice().reverse().map((item, i) => (
                              <div key={i} className="snap-start">
                                  <SongCard item={item} onPlay={() => playSong(item, daylist)} />
                              </div>
                          ))
                      )}
                  </div>
              </motion.section>
          )}

      </div>
    </div>
  );
};
